import React from 'react';
import { Button } from '../components/Button';
import { Card } from '../components/Card';
import { useFlowStore } from '../store/flowStore';
import { useQuizStore } from '../store/quizStore';
import { soundService } from '../services/soundService';
import { ScreenContainer, Header, InfoRow } from '../components/screen';

/**
 * QuizSettingsScreen Component
 * Màn hình xác nhận trước khi làm bài (đã chọn số lượng câu hỏi)
 */
export const QuizSettingsScreen = () => {
  const { goToNext, goBack } = useFlowStore();
  const { currentLesson, questionCount, quizSettings } = useQuizStore();

  const handleBack = () => {
    soundService.playClick();
    goBack();
  };

  const handleStart = () => {
    soundService.playClick();
    goToNext('quiz');
  };

  return (
    <ScreenContainer maxWidth="2xl">
      <Header
        title="Xác nhận bài làm"
        titleClassName="text-4xl"
        showBackButton={true}
        onBack={handleBack}
      />

      <Card>
        <div className="space-y-6">
          <div className="text-center">
            <div className="text-6xl mb-4">{currentLesson?.icon}</div>
            <h2 className="text-2xl font-bold text-gray-800 mb-2">
              {currentLesson?.name}
            </h2>
            <p className="text-gray-600 mb-4">{currentLesson?.description}</p>
          </div>

          <div className="bg-gray-50 rounded-lg p-4 space-y-3">
            <InfoRow
              label="Số lượng câu hỏi:"
              value={`${questionCount || 10} câu`}
              valueClassName="text-primary-600 font-bold"
            />
            <InfoRow
              label="Chế độ tính điểm:"
              value={quizSettings?.scoringMode === 'time' ? 'Theo thời gian' : 'Cơ bản'}
            />
            <InfoRow
              label="Thời gian mỗi câu:"
              value={quizSettings?.timeLimit === 0 ? 'Không giới hạn' : `${quizSettings?.timeLimit || 30}s`}
            />
          </div>

          <div className="flex flex-col items-center gap-2 text-sm text-gray-500">
            <p>💡 Bạn có thể tinh chỉnh chi tiết hơn trước khi bắt đầu.</p>
            <Button
              variant="outline"
              size="sm"
              onClick={() => goToNext('settings')}
              className="mt-1"
            >
              ⚙️ Mở cài đặt chi tiết
            </Button>
          </div>

          <div className="flex gap-4 pt-4">
            <Button
              onClick={handleStart}
              variant="primary"
              size="lg"
              className="flex-1"
            >
              Bắt đầu! 🎯
            </Button>
            <Button
              onClick={handleBack}
              variant="outline"
              size="lg"
              className="flex-1"
            >
              Hủy bỏ
            </Button>
          </div>
        </div>
      </Card>

      {/* Nút Back ở footer */}
      <div className="mt-8 text-center">
        <Button
          onClick={handleBack}
          variant="outline"
          size="md"
        >
          ← Quay lại
        </Button>
      </div>
    </ScreenContainer>
  );
};

